Here's the full setup:

**XAML — wrap `CollectionView` in `RefreshView`:**

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="48,*">
                    <Image Source="{Binding Icon}"
                           WidthRequest="40" HeightRequest="40" />
                    <Label Grid.Column="1"
                           Text="{Binding Name}"
                           VerticalOptions="Center" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <Label Text="No items found."
                   HorizontalOptions="Center"
                   VerticalOptions="Center" />
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

**ViewModel (using CommunityToolkit.Mvvm):**

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IItemService _service;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private Item? currentItem;

    [ObservableProperty]
    private bool isRefreshing;

    public ObservableCollection<Item> Items { get; } = new();

    public ItemsViewModel(IItemService service, INavigationService nav)
    {
        _service = service;
        _nav = nav;
    }

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (CurrentItem is null) return;

        await _nav.GoToAsync($"details?id={CurrentItem.Id}");
        CurrentItem = null; // reset so user can re-select the same item
    }

    [RelayCommand]
    private async Task Refresh()
    {
        try
        {
            var data = await _service.GetItemsAsync();
            Items.Clear();
            foreach (var item in data)
                Items.Add(item);
        }
        finally
        {
            IsRefreshing = false; // must set false to dismiss the spinner
        }
    }
}
```

**Key bindings explained:**

| Property | Purpose |
|---|---|
| `ItemsSource="{Binding Items}"` | Bind to `ObservableCollection<T>` so adds/removes auto-update the UI |
| `SelectedItem="{Binding CurrentItem, Mode=TwoWay}"` | Tracks the selected item; `TwoWay` so you can reset it from code |
| `SelectionChangedCommand` | Fires when selection changes — use it to navigate |
| `IsRefreshing="{Binding IsRefreshing}"` | Controls the refresh spinner; **set to `false` when done** |
| `Command="{Binding RefreshCommand}"` | Fires on pull-to-refresh gesture |

**Important notes:**
- Reset `CurrentItem = null` after navigation so the same item can be re-selected.
- Always set `IsRefreshing = false` in a `finally` block to guarantee the spinner dismisses.
- Use `ObservableCollection<T>`, never `List<T>` — swapping a `List` forces a full re-render.
- Set `x:DataType` on the `DataTemplate` for compiled bindings.
